package com.example.salaryadvancesystem

import android.os.Bundle
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.activity.enableEdgeToEdge
import androidx.compose.foundation.layout.fillMaxSize
import androidx.compose.foundation.layout.padding
import androidx.compose.material3.Scaffold
import androidx.compose.material3.Text
import androidx.compose.runtime.Composable
import androidx.compose.ui.Modifier
import androidx.compose.ui.tooling.preview.Preview
import com.example.salaryadvancesystem.ui.theme.SalaryAdvanceSystemTheme

class MainActivity : ComponentActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContent {
            SalaryAdvanceSystemTheme {
                Scaffold(modifier = Modifier.fillMaxSize()) { innerPadding ->
                    Greeting(
                        name = "Android",
                        modifier = Modifier.padding(innerPadding)
                    )
                }
            }
        }
    }
}

@Composable
fun Greeting(name: String, modifier: Modifier = Modifier) {
    Text(
        text = "Hello $name!",
        modifier = modifier
    )
}

@Preview(showBackground = true)
@Composable
fun GreetingPreview() {
    SalaryAdvanceSystemTheme {
        Greeting("Android")
    }
}

package com.example.salaryadvancesystem

import android.os.Bundle
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.activity.enableEdgeToEdge
import androidx.compose.foundation.layout.fillMaxSize
import androidx.compose.foundation.layout.padding
import androidx.compose.material3.Scaffold
import androidx.compose.material3.Text
import androidx.compose.runtime.Composable
import androidx.compose.ui.Modifier
import androidx.compose.ui.tooling.preview.Preview
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import androidx.navigation.compose.rememberNavController
import com.example.salaryadvancesystem.screens.ApplyAdvanceScreen
import com.example.salaryadvancesystem.screens.DashboardScreen
import com.example.salaryadvancesystem.screens.LoanStatusScreen
import com.example.salaryadvancesystem.screens.LoanSummaryScreen
import com.example.salaryadvancesystem.ui.theme.SalaryAdvanceSystemTheme

class MainActivity : ComponentActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContent {
            SalaryAdvanceSystemTheme {
                val navController = rememberNavController()
                NavHost(navController = navController, startDestination = "dashboard") {
                    composable("dashboard") {
                        DashboardScreen(navController, dummyEmployee)
                    }
                    composable("apply_advance") {
                        ApplyAdvanceScreen(navController, dummyEmployee)
                    }
                    composable("loan_summary/{amount}/{serviceCharge}/{netAmount}/{purpose}") { backStackEntry ->
                        val amount = backStackEntry.arguments?.getString("amount")?.toDoubleOrNull() ?: 0.0
                        val serviceCharge = backStackEntry.arguments?.getString("serviceCharge")?.toDoubleOrNull() ?: 0.0
                        val netAmount = backStackEntry.arguments?.getString("netAmount")?.toDoubleOrNull() ?: 0.0
                        val purpose = backStackEntry.arguments?.getString("purpose") ?: ""
                        LoanSummaryScreen(navController, amount, serviceCharge, netAmount, purpose)
                    }
                    composable("loan_status") {
                        LoanStatusScreen(navController)
                    }
                }
            }
        }
    }
}

@Composable
fun Greeting(name: String, modifier: Modifier = Modifier) {
    Text(
        text = "Hello $name!",
        modifier = modifier
    )
}

@Preview(showBackground = true)
@Composable
fun GreetingPreview() {
    SalaryAdvanceSystemTheme {
        Greeting("Android")
    }
}
